// App.jsx
import { Routes, Route, Navigate } from "react-router-dom";
import { useState } from "react";

// Halaman Auth
import Register from "./Pages/Auth/Register";
import Login from "./Pages/Auth/Login";
import Logout from "./Pages/Auth/Logout";

// Halaman Dashboard
import Dashboard from "./Pages/Dashboard/Dashboard";
import DashboardSuperAdmin from "./Pages/Dashboard/DashboardSuperAdmin";

// Halaman Menu
import MasterData from "./Pages/MasterData/MasterData";
import Tracking from "./Pages/Tracking/Tracking";

// Perhatikan path sesuai struktur folder kamu
import InfoDriver from "./Pages/Auth/InfoDriver/InfoDriver"; // Path sesuai folder
import ByPass from "./Pages/Auth/ByPass/ByPass"; // Path sesuai folder
import Settings from "./Pages/Auth/Settings/Settings"; // Path sesuai folder

export default function App() {
  const [userRole, setUserRole] = useState(null);
  const isLoggedIn = !!userRole;

  // Fungsi untuk membatasi akses berdasarkan role
  const protectedRoute = (element, allowedRoles) => {
    if (!isLoggedIn) return <Navigate to="/login" />;
    if (!allowedRoles.includes(userRole)) return <Navigate to="/dashboard" />;
    return element;
  };

  return (
    <Routes>
      {/* Auth */}
      <Route path="/register" element={<Register />} />
      <Route path="/login" element={<Login setUserRole={setUserRole} />} />
      <Route path="/logout" element={<Logout setUserRole={setUserRole} />} />

      {/* Dashboard dibedakan jika Super Admin */}
      <Route
        path="/dashboard"
        element={
          isLoggedIn ? (
            userRole === "Super Admin" ? (
              <DashboardSuperAdmin role={userRole} />
            ) : (
              <Dashboard role={userRole} />
            )
          ) : (
            <Navigate to="/login" />
          )
        }
      />

      {/* Admin Only */}
      <Route
        path="/master-data"
        element={protectedRoute(<MasterData role={userRole} />, ["Admin"])}
      />

      {/* Super Admin Only */}
      <Route
        path="/bypass"
        element={protectedRoute(<ByPass role={userRole} />, ["Super Admin"])}
      />

      {/* Admin dan Super Admin */}
      <Route
        path="/tracking"
        element={protectedRoute(<Tracking role={userRole} />, ["Admin", "Super Admin"])}
      />
      <Route
        path="/info-driver"
        element={protectedRoute(<InfoDriver role={userRole} />, ["Admin", "Super Admin"])}
      />
      <Route
        path="/settings"
        element={protectedRoute(<Settings role={userRole} />, ["Admin", "Super Admin"])}
      />

      {/* Redirect all other routes */}
      <Route path="*" element={<Navigate to="/login" />} />
    </Routes>
  );
}
